// Assuming the UserRole enum is defined somewhere in the codebase
enum UserRole {
    Admin = 'Admin',
    Reviewer = 'Reviewer',
    // Removed Submitter and Talent roles
}

// Example of a user entity
class User {
    constructor(public id: string, public role: UserRole) {}
}

// Function that checks user permissions
function canSubmitReview(user: User): boolean {
    return user.role === UserRole.Admin || user.role === UserRole.Reviewer;
}

// Example of a function that processes submissions
function processSubmission(user: User): string {
    if (!canSubmitReview(user)) {
        throw new Error('User does not have permission to submit a review');
    }
    return 'Submission processed';
}

// Unit tests for critical behaviors
describe('User Role Tests', () => {
    it('should allow Admin to submit a review', () => {
        const user = new User('1', UserRole.Admin);
        expect(processSubmission(user)).toEqual('Submission processed');
    });

    it('should allow Reviewer to submit a review', () => {
        const user = new User('2', UserRole.Reviewer);
        expect(processSubmission(user)).toEqual('Submission processed');
    });

    it('should not allow other roles to submit a review', () => {
        const user = new User('3', UserRole.Reviewer); // Assuming this is a generic user now
        expect(() => processSubmission(user)).toThrow('User does not have permission to submit a review');
    });
});
